import{_ as e,c as n,a,b as r,d as i,r as o,o as s}from"./app-DxT-J_20.js";const l={};function h(c,t){const d=o("DateMeta");return s(),n("div",null,[t[0]||(t[0]=a("h1",{id:"파킹통장-vs-cma-통장",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#파킹통장-vs-cma-통장"},[a("span",null,"파킹통장 vs CMA 통장")])],-1)),r(d),t[1]||(t[1]=i('<p>여유 자금을 잠깐 보관할 때 이자를 받을 수 있는 대표적인 두 가지 수단이 파킹통장과 CMA 통장이다. 둘 다 수시 입출금이 가능하면서 일반 보통예금보다 높은 금리를 제공하지만, 구조와 안전성 면에서 차이가 있다.</p><h2 id="파킹통장" tabindex="-1"><a class="header-anchor" href="#파킹통장"><span>파킹통장</span></a></h2><h3 id="개념" tabindex="-1"><a class="header-anchor" href="#개념"><span>개념</span></a></h3><p>파킹통장(Parking Account)은 은행에서 제공하는 수시 입출금 예금 상품 중, 일반 보통예금보다 높은 금리를 제공하는 통장을 통칭한다. 차를 잠깐 &#39;주차&#39;하듯 자금을 잠시 보관하는 용도에서 이름이 붙었다.</p><h3 id="특징" tabindex="-1"><a class="header-anchor" href="#특징"><span>특징</span></a></h3><ul><li>운영 주체: <strong>은행</strong></li><li>예금자보호 여부: <strong>보호 (1인 1금융기관 기준 최대 1억원)</strong></li><li>이자 계산 방식: 일별 잔액 기준, 매월 말 지급 (상품마다 다름)</li><li>입출금: 자유롭게 가능 (공과금 자동이체, 체크카드 연결 등 가능)</li></ul><h3 id="주요-상품-비교-2024-2025년-기준" tabindex="-1"><a class="header-anchor" href="#주요-상품-비교-2024-2025년-기준"><span>주요 상품 비교 (2024~2025년 기준)</span></a></h3><table><thead><tr><th>상품명</th><th>은행</th><th>금리</th><th>조건</th></tr></thead><tbody><tr><td>케이뱅크 플러스박스</td><td>케이뱅크</td><td>최대 2.3%</td><td>월 이자 지급, 잔액 구간별 금리</td></tr><tr><td>카카오뱅크 세이프박스</td><td>카카오뱅크</td><td>2.0%</td><td>최대 1억원, 수시 입출금</td></tr><tr><td>토스뱅크 통장</td><td>토스뱅크</td><td>1.4~2.0%</td><td>잔액 전액 금리 적용</td></tr><tr><td>SC제일은행 파킹통장</td><td>SC제일은행</td><td>2.0~2.5%</td><td>우대조건 충족 시</td></tr></tbody></table><blockquote><p>금리는 한국은행 기준금리 변동에 따라 주기적으로 조정된다. 가입 전 최신 금리를 확인할 것.</p></blockquote><h3 id="장단점" tabindex="-1"><a class="header-anchor" href="#장단점"><span>장단점</span></a></h3><p><strong>장점</strong></p><ul><li>예금자보호 적용 (최대 1억원)</li><li>체크카드, 자동이체 등 은행 서비스와 연동 가능</li><li>입출금이 즉시 처리됨</li></ul><p><strong>단점</strong></p><ul><li>증권사 CMA 대비 금리가 낮은 경우가 있음</li><li>인터넷 전문은행 외 시중은행 파킹통장은 금리가 낮거나 조건이 복잡함</li></ul><h2 id="cma-통장" tabindex="-1"><a class="header-anchor" href="#cma-통장"><span>CMA 통장</span></a></h2><h3 id="개념-1" tabindex="-1"><a class="header-anchor" href="#개념-1"><span>개념</span></a></h3><p>CMA(Cash Management Account)는 증권사에서 운영하는 단기 금융상품이다. 고객이 예치한 자금을 단기 채권, RP(환매조건부채권), MMF 등에 운용해 수익을 내고, 그 수익을 이자로 지급하는 구조다.</p><h3 id="종류" tabindex="-1"><a class="header-anchor" href="#종류"><span>종류</span></a></h3><table><thead><tr><th>유형</th><th>운용 방식</th><th>특징</th></tr></thead><tbody><tr><td>RP형</td><td>증권사가 보유한 국채·공사채 등을 담보로 운용</td><td>가장 일반적, 금리 비교적 높음</td></tr><tr><td>MMF형</td><td>단기 채권 펀드에 투자</td><td>원금 손실 가능성 매우 낮음 (극히 드뭄)</td></tr><tr><td>발행어음형</td><td>증권사가 자체 발행한 어음</td><td>높은 금리, 단 예금자보호 미적용</td></tr><tr><td>종금형</td><td>종합금융회사 운영 (현재 극소수)</td><td>예금자보호 적용 (1억원)</td></tr></tbody></table><h3 id="주요-cma-금리-비교-2024-2025년-기준" tabindex="-1"><a class="header-anchor" href="#주요-cma-금리-비교-2024-2025년-기준"><span>주요 CMA 금리 비교 (2024~2025년 기준)</span></a></h3><table><thead><tr><th>상품</th><th>증권사</th><th>금리</th><th>예금자보호</th></tr></thead><tbody><tr><td>미래에셋 CMA (RP형)</td><td>미래에셋증권</td><td>3.2~3.5%</td><td>미적용</td></tr><tr><td>한국투자증권 CMA</td><td>한투증권</td><td>3.0~3.4%</td><td>미적용</td></tr><tr><td>삼성증권 CMA (발행어음)</td><td>삼성증권</td><td>3.5%</td><td>미적용</td></tr><tr><td>NH투자증권 CMA</td><td>NH증권</td><td>3.0~3.3%</td><td>미적용</td></tr></tbody></table><blockquote><p>CMA 금리는 파킹통장보다 높은 경우가 많지만, <strong>예금자보호가 적용되지 않는다</strong>는 점이 핵심 차이다.</p></blockquote><h3 id="특징-1" tabindex="-1"><a class="header-anchor" href="#특징-1"><span>특징</span></a></h3><ul><li>운영 주체: <strong>증권사</strong></li><li>예금자보호 여부: <strong>대부분 미적용</strong> (종금형 제외)</li><li>이자 계산: 일별 복리 지급 (일부 상품은 매일 이자 지급)</li><li>입출금: 자유롭게 가능 (체크카드 연결 가능)</li><li>증권 거래: CMA 계좌에서 주식, ETF 매수 바로 가능</li></ul><h3 id="장단점-1" tabindex="-1"><a class="header-anchor" href="#장단점-1"><span>장단점</span></a></h3><p><strong>장점</strong></p><ul><li>파킹통장 대비 금리가 높은 경우가 많음</li><li>주식·ETF 투자와 연동해서 쓰기 편리</li><li>매일 이자가 들어오는 상품도 있어 복리 효과</li></ul><p><strong>단점</strong></p><ul><li><strong>예금자보호 미적용</strong> (증권사 파산 시 원금 손실 가능성)</li><li>은행 자동이체, 월급 이체 설정이 은행 계좌보다 번거로울 수 있음</li></ul><h2 id="파킹통장-vs-cma-핵심-비교" tabindex="-1"><a class="header-anchor" href="#파킹통장-vs-cma-핵심-비교"><span>파킹통장 vs CMA 핵심 비교</span></a></h2><table><thead><tr><th>항목</th><th>파킹통장 (은행)</th><th>CMA (증권사)</th></tr></thead><tbody><tr><td>운영 주체</td><td>은행</td><td>증권사</td></tr><tr><td>예금자보호</td><td><strong>적용 (최대 1억원)</strong></td><td>대부분 미적용</td></tr><tr><td>금리 수준</td><td>1.5~2.5%</td><td>3.0~3.5%</td></tr><tr><td>이자 지급</td><td>월 1회 (대부분)</td><td>일별 (일부 상품)</td></tr><tr><td>체크카드 연결</td><td>가능</td><td>가능 (일부)</td></tr><tr><td>주식/ETF 매수</td><td>불가</td><td>가능</td></tr><tr><td>자동이체 편의성</td><td>높음</td><td>낮음</td></tr></tbody></table><h2 id="어떤-것을-선택해야-할까" tabindex="-1"><a class="header-anchor" href="#어떤-것을-선택해야-할까"><span>어떤 것을 선택해야 할까?</span></a></h2><h3 id="파킹통장이-적합한-경우" tabindex="-1"><a class="header-anchor" href="#파킹통장이-적합한-경우"><span>파킹통장이 적합한 경우</span></a></h3><ul><li>원금 보호(예금자보호)가 최우선인 경우</li><li>공과금 자동이체, 월급 계좌와 연동이 필요한 경우</li><li>1억원 이하의 단기 자금 보관</li><li>은행 서비스가 익숙하고 간편하게 쓰고 싶은 경우</li></ul><h3 id="cma가-적합한-경우" tabindex="-1"><a class="header-anchor" href="#cma가-적합한-경우"><span>CMA가 적합한 경우</span></a></h3><ul><li>조금이라도 더 높은 금리를 원하는 경우</li><li>이미 증권 계좌를 사용 중이거나 주식·ETF 투자와 연동하고 싶은 경우</li><li>소액 (수백만원 이하)이라 예금자보호 필요성이 낮다고 판단하는 경우</li></ul><h3 id="현실적인-전략" tabindex="-1"><a class="header-anchor" href="#현실적인-전략"><span>현실적인 전략</span></a></h3><p>1억원 이하 단기 자금이라면 <strong>파킹통장</strong>이 안정적이다. 금리 차이(0.5~1%p)가 있지만, 예금자보호가 주는 안전성은 그 이상의 가치가 있다.</p><p>1억원 초과 여유 자금이라면 어차피 예금자보호를 초과하므로, CMA의 높은 금리를 선택하거나 두 상품을 분산해서 사용하는 것이 현명하다.</p><div class="hint-container info"><p class="hint-container-title">금리 변동 주의</p><p>파킹통장과 CMA 금리는 한국은행 기준금리에 연동해 변동한다. 기준금리 인하 시 두 상품 모두 금리가 내려가므로, 현재 공시 금리가 미래에도 유지된다고 보장할 수 없다.</p></div><div class="hint-container warning"><p class="hint-container-title">예금자보호 한도</p><p>예금자보호는 1인 1금융기관(은행) 기준 원금+이자 합산 <strong>1억원</strong>까지 보호한다. 2개 이상의 은행에 나눠 예치하면 각 은행별로 1억원까지 보호받는다. 증권사 RP형 CMA는 예금자보호 대상이 아니다.</p></div>',41))])}const m=e(l,[["render",h]]),g=JSON.parse('{"path":"/finance/parking-account-cma.html","title":"파킹통장 vs CMA 통장","lang":"ko-KR","frontmatter":{"description":"파킹통장 vs CMA 통장","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"파킹통장 vs CMA 통장\\",\\"image\\":[\\"https://kmbzn.com/images/og.png\\"],\\"dateModified\\":\\"2026-06-12T15:12:24.000Z\\",\\"author\\":[]}"],["meta",{"property":"og:url","content":"https://kmbzn.com/finance/parking-account-cma.html"}],["meta",{"property":"og:title","content":"파킹통장 vs CMA 통장"}],["meta",{"property":"og:description","content":"파킹통장 vs CMA 통장"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://kmbzn.com/images/og.png"}],["meta",{"property":"og:locale","content":"ko-KR"}],["meta",{"property":"og:updated_time","content":"2026-06-12T15:12:24.000Z"}],["meta",{"property":"article:modified_time","content":"2026-06-12T15:12:24.000Z"}]]},"git":{"createdTime":1781276728000,"updatedTime":1781277144000,"contributors":[{"name":"kmbzn","username":"kmbzn","email":"kmbzn24@gmail.com","commits":2,"url":"https://github.com/kmbzn"},{"name":"Claude Sonnet 4.6","username":"","email":"noreply@anthropic.com","commits":2}],"changelog":[{"hash":"867901d169b73496a8a67d2853b6d0b27bdbf876","time":1781277144000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"docs: rename all files to lowercase and add Products/Finance articles","coAuthors":[{"name":"Claude Sonnet 4.6","email":"noreply@anthropic.com"}]},{"hash":"3c8679f3d167cb8c2288aa7b14832c355376d4a3","time":1781276728000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"docs: add Brands (AESTRUA, JINHAO, Herman Miller) and Finance section","coAuthors":[{"name":"Claude Sonnet 4.6","email":"noreply@anthropic.com"}]}]},"filePathRelative":"finance/parking-account-cma.md","autoDesc":true}');export{m as comp,g as data};
